// Validate the id_token claims
function validateIdTokenClaims(decoded, nonce) {
  const errors = [];

  if (!decoded) {
    errors.push('Failed to decode id_token');
    return errors;
  }

  // Validate issuer
  if (decoded.iss !== OIDC_CONFIG.issuer) {
    errors.push(`Invalid issuer. Expected: ${OIDC_CONFIG.issuer}, Got: ${decoded.iss}`);
  }

  // Validate audience
  if (decoded.aud !== OIDC_CONFIG.clientId) {
    if (Array.isArray(decoded.aud) && !decoded.aud.includes(OIDC_CONFIG.clientId)) {
      errors.push(`Invalid audience. Expected: ${OIDC_CONFIG.clientId}, Got: ${decoded.aud}`);
    } else if (!Array.isArray(decoded.aud) && decoded.aud !== OIDC_CONFIG.clientId) {
      errors.push(`Invalid audience. Expected: ${OIDC_CONFIG.clientId}, Got: ${decoded.aud}`);
    }
  }

  // Validate expiration
  const now = Math.floor(Date.now() / 1000);
  if (decoded.exp && decoded.exp < now) {
    errors.push('Token has expired');
  }

  // Validate issued at (with 5 minute clock skew tolerance)
  if (decoded.iat && decoded.iat > now + 300) {
    errors.push('Token issued in the future');
  }

  // Validate nonce if provided
  if (nonce && decoded.nonce !== nonce) {
    errors.push('Invalid nonce');
  }

  // Validate subject exists
  if (!decoded.sub) {
    errors.push('Missing subject (sub) claim');
  }

  return errors;
}

